@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@500;600;700;800&display=swap');
:root{--bg:#fbf7fd;--surface:#fff;--ink:#14233b;--muted:rgba(20,35,59,.66);--line:rgba(20,35,59,.09);--brand-a:#d70a7c;--brand-b:#1d9bf0;--brand-deep:#5a1687;--danger:#9a3737;--shadow:0 28px 72px rgba(20,35,59,.11)}
