.studio-card{background:var(--surface);border:1px solid var(--line);border-radius:24px;box-shadow:var(--shadow);padding:28px}.studio-head{display:flex;justify-content:space-between;gap:16px;align-items:flex-start;flex-wrap:wrap;margin-bottom:18px}.studio-head h2{margin:0;font-size:32px;line-height:1;letter-spacing:-.04em}.studio-head p{margin:8px 0 0;color:var(--muted);max-width:46ch;line-height:1.6}.studio-chip{display:inline-flex;align-items:center;padding:9px 12px;border-radius:999px;background:linear-gradient(135deg,rgba(215,10,124,.08),rgba(29,155,240,.08));color:var(--brand-deep);font-size:12px;font-weight:800}
