.studio-grid-2,.studio-grid-3,.studio-metrics{display:grid;gap:16px}.studio-grid-2{grid-template-columns:repeat(2,minmax(0,1fr))}.studio-grid-3{grid-template-columns:repeat(3,minmax(0,1fr))}
