.tip{position:relative;display:inline-flex;align-items:center;justify-content:center;width:20px;height:20px;border-radius:999px;background:rgba(9,44,51,.08);color:var(--muted);font-size:12px;font-weight:800;cursor:help;outline:none}.tip::after{content:attr(data-tip);position:absolute;left:50%;bottom:calc(100% + 10px);transform:translateX(-50%);min-width:180px;max-width:240px;padding:10px 12px;border-radius:12px;background:#07262d;color:#fff;font-size:12px;line-height:1.45;opacity:0;visibility:hidden;transition:.16s ease;pointer-events:none;box-shadow:0 20px 34px rgba(9,44,51,.24)}.tip:hover::after,.tip:focus::after{opacity:1;visibility:visible}
.field-card input,.field-card select{width:100%;height:52px;padding:0 16px;border-radius:14px;border:1px solid rgba(20,35,59,.12);background:#fff;font:inherit;color:var(--ink)}.field-card input:focus,.field-card select:focus{outline:none;border-color:rgba(215,10,124,.35);box-shadow:0 0 0 4px rgba(29,155,240,.1)}
