table{width:100%;border-collapse:collapse}th,td{padding:14px 16px;border-bottom:1px solid rgba(9,44,51,.06);text-align:left}th{font-size:12px;letter-spacing:.08em;text-transform:uppercase;color:rgba(9,44,51,.56)}
.studio-actions{display:flex;justify-content:space-between;gap:12px;flex-wrap:wrap;margin-top:24px;padding-top:18px;border-top:1px solid var(--line)}.studio-actions-left,.studio-actions-right{display:flex;gap:12px;flex-wrap:wrap}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:50px;padding:0 20px;border:none;border-radius:14px;font:inherit;font-weight:800;text-decoration:none;cursor:pointer}.btn-primary{background:linear-gradient(135deg,var(--brand-a) 0%,var(--brand-b) 100%);color:#fff}.btn-secondary{background:#fff;color:var(--ink);border:1px solid rgba(20,35,59,.12)}.btn[disabled]{opacity:.56;cursor:not-allowed}.hidden{display:none!important}.success-box{padding:18px;border-radius:18px;background:linear-gradient(135deg,rgba(215,10,124,.06),rgba(29,155,240,.06));border:1px solid rgba(90,22,135,.12)}.success-actions{display:flex;gap:12px;flex-wrap:wrap;margin-top:14px}
