<div class="studio-shell"><div class="studio-top"><div><span class="studio-brand">Liquid CP</span><div class="support">By Liquid Intelligent Technologies Zambia</div><h1 class="studio-title">Estimate Studio</h1><p class="studio-subtitle">Phase 1 quotation flow</p></div></div>
<div class="studio-progress"><div class="studio-step active" data-step-pill="1"><strong>01. Context</strong><span>Quote identity</span></div><div class="studio-step" data-step-pill="2"><strong>02. Build</strong><span>Manual inputs</span></div><div class="studio-step" data-step-pill="3"><strong>03. Review</strong><span>Estimate output</span></div><div class="studio-step" data-step-pill="4"><strong>04. Save</strong><span>Snapshot</span></div></div>
<div class="studio-card"><form id="liquidcp-wizard-form"><input type="hidden" name="<?php echo html_escape($csrf_token_name); ?>" id="liquidcp-csrf-token" value="<?php echo html_escape($csrf_hash); ?>"><div id="liquidcp-validation" class="studio-error hidden"></div>
<section class="studio-stage active" data-step="1"><div class="studio-head"><div><h2>Set the estimate context</h2><p>Capture the commercial identity first, then move straight into pricing inputs.</p></div><div class="studio-chip">Required before pricing</div></div><input id="company_name" name="company_name" type="hidden" value="Liquid Intelligent Technologies Zambia"><div class="studio-grid-2"><div class="field-card"><div class="label-row"><label for="client_name">Client name</label><span class="tip" tabindex="0" data-tip="Name shown on the saved quotation and public quote page.">?</span></div><input id="client_name" name="client_name" value="Prototype Client"></div><div class="field-card"><div class="label-row"><label for="client_email">Client email</label><span class="tip" tabindex="0" data-tip="Contact email stored with the estimate snapshot.">?</span></div><input id="client_email" name="client_email" value="client@example.com"></div><div class="field-card"><div class="label-row"><label for="quote_title">Quote title</label><span class="tip" tabindex="0" data-tip="Short commercial label used to identify the estimate.">?</span></div><input id="quote_title" name="quote_title" value="Phase 1 fibre build estimate"></div></div></section>
<section class="studio-stage" data-step="2"><div class="studio-head"><div><h2>Enter build inputs</h2><p>Only workbook-aligned Phase 1 inputs are exposed here.</p></div><div class="studio-chip">Seeded ruleset</div></div><div class="studio-grid-3"><div class="field-card"><div class="label-row"><label for="build_profile">Build profile</label><span class="tip" tabindex="0" data-tip="Phase 1 keeps a single seeded build profile tied to the active ruleset.">?</span></div><select id="build_profile" name="build_profile"><option value="prototype-general">Prototype General</option></select></div><div class="field-card"><div class="label-row"><label for="distance_new_aerial">New aerial (m)</label><span class="tip" tabindex="0" data-tip="Primary aerial construction distance used by the pricing engine.">?</span></div><input id="distance_new_aerial" type="number" step="0.01" min="0" name="distance_new_aerial" value="<?php echo html_escape($defaults['distance_new_aerial']); ?>"></div><div class="field-card"><div class="label-row"><label for="distance_new_underground">New underground (m)</label><span class="tip" tabindex="0" data-tip="Underground construction distance for the route.">?</span></div><input id="distance_new_underground" type="number" step="0.01" min="0" name="distance_new_underground" value="<?php echo html_escape($defaults['distance_new_underground']); ?>"></div><div class="field-card"><div class="label-row"><label for="distance_existing_aerial">Existing aerial (m)</label><span class="tip" tabindex="0" data-tip="Distance carried on existing aerial infrastructure instead of new build.">?</span></div><input id="distance_existing_aerial" type="number" step="0.01" min="0" name="distance_existing_aerial" value="<?php echo html_escape($defaults['distance_existing_aerial']); ?>"></div><div class="field-card"><div class="label-row"><label for="distance_existing_duct">Existing duct (m)</label><span class="tip" tabindex="0" data-tip="Distance carried in existing duct infrastructure.">?</span></div><input id="distance_existing_duct" type="number" step="0.01" min="0" name="distance_existing_duct" value="<?php echo html_escape($defaults['distance_existing_duct']); ?>"></div><div class="field-card"><div class="label-row"><label for="customer_nrc">Customer NRC (ZMW)</label><span class="tip" tabindex="0" data-tip="Non-recurring customer charge applied when calculating net build cost.">?</span></div><input id="customer_nrc" type="number" step="0.01" min="0" name="customer_nrc" value="<?php echo html_escape($defaults['customer_nrc']); ?>"></div><div class="field-card"><div class="label-row"><label for="customer_mrc">Customer MRC (ZMW)</label><span class="tip" tabindex="0" data-tip="Recurring customer charge used for ROI timing.">?</span></div><input id="customer_mrc" type="number" step="0.01" min="0" name="customer_mrc" value="<?php echo html_escape($defaults['customer_mrc']); ?>"></div><div class="field-card"><div class="label-row"><label for="exchange_rate">Exchange rate</label><span class="tip" tabindex="0" data-tip="Applied against the ruleset-driven equipment assumptions.">?</span></div><input id="exchange_rate" type="number" step="0.01" min="0" name="exchange_rate" value="<?php echo html_escape($defaults['exchange_rate']); ?>"></div></div></section>
<section class="studio-stage" data-step="3"><div class="studio-head"><div><h2>Review the estimate</h2><p>Inspect totals, validate the breakdown, and confirm the output before saving.</p></div><div class="studio-chip">Auto-calculated</div></div><div id="liquidcp-engine-message" class="studio-banner">Your estimate will appear here after build inputs are processed.</div><div id="liquidcp-summary" class="hidden"><div class="studio-metrics"><div class="metric-card"><span>Labour</span><strong id="metric-labour">-</strong></div><div class="metric-card"><span>Materials</span><strong id="metric-materials">-</strong></div><div class="metric-card"><span>Admin</span><strong id="metric-admin">-</strong></div><div class="metric-card"><span>Wayleave</span><strong id="metric-wayleave">-</strong></div><div class="metric-card"><span>VAT</span><strong id="metric-vat">-</strong></div><div class="metric-card"><span>Total due</span><strong id="metric-total">-</strong></div><div class="metric-card"><span>Net build cost</span><strong id="metric-net-build-cost">-</strong></div><div class="metric-card"><span>ROI years</span><strong id="metric-roi-years">-</strong></div></div><div class="studio-review"><div id="liquidcp-line-items"></div><aside><div class="summary-panel"><h3>Snapshot</h3><div id="liquidcp-summary-chips"></div></div><div class="summary-panel" style="margin-top:14px;"><h3>ROI</h3><div class="metric-card" style="padding:16px;"><span>ROI months</span><strong id="metric-roi-months">-</strong></div></div><div class="summary-panel" style="margin-top:14px;"><h3>Warnings</h3><ul id="liquidcp-warning-list"><li>No warnings yet.</li></ul></div></aside></div></div></section>
<section class="studio-stage" data-step="4"><div class="studio-head"><div><h2>Save the snapshot</h2><p>Saving freezes the request, engine response, ruleset version, and quote outputs.</p></div><div class="studio-chip">Snapshot only</div></div><div id="liquidcp-save-message" class="studio-banner studio-warn">Run an estimate before saving.</div><div class="studio-grid-2"><div class="summary-panel"><h3>Phase 1 note</h3><p><?php echo html_escape($prototype_disclaimer); ?></p></div><div class="summary-panel"><h3>Stored with every save</h3><p>Quote metadata, input snapshot, engine response, totals, versions, and PDF reference.</p></div></div><div id="liquidcp-save-results" class="hidden" style="margin-top:18px;"></div></section>
<div class="studio-actions"><div class="studio-actions-left"><button type="button" class="btn btn-secondary" id="liquidcp-prev-btn">Back</button><button type="button" class="btn btn-primary" id="liquidcp-next-btn">Next</button></div><div class="studio-actions-right"><button type="button" class="btn btn-primary hidden" id="liquidcp-save-btn">Save estimate</button></div></div></form></div></div>
<script type="text/javascript">
(function ($) { var currentStep = 1; var latestEstimate = null; var estimateFingerprint = ''; var isEstimating = false; var defaultNextLabel = 'Next'; function formatMoney(value){ if(value===null||typeof value==='undefined'){ return '-'; } return 'ZMW ' + Number(value).toLocaleString(undefined,{ minimumFractionDigits:2, maximumFractionDigits:2 }); } function numberValue(name){ return Number($('*[name="' + name + '"]').val() || 0); } function setValidation(message){ $('#liquidcp-validation').toggleClass('hidden', !message).text(message || ''); } function buildFingerprint(){ return JSON.stringify({ client_name:$('input[name="client_name"]').val().trim(), client_email:$('input[name="client_email"]').val().trim(), company_name:$('input[name="company_name"]').val().trim(), quote_title:$('input[name="quote_title"]').val().trim(), build_profile:$('select[name="build_profile"]').val(), distance_new_aerial:numberValue('distance_new_aerial'), distance_new_underground:numberValue('distance_new_underground'), distance_existing_aerial:numberValue('distance_existing_aerial'), distance_existing_duct:numberValue('distance_existing_duct'), customer_nrc:numberValue('customer_nrc'), customer_mrc:numberValue('customer_mrc'), exchange_rate:numberValue('exchange_rate') }); } function invalidateEstimate(){ latestEstimate = null; estimateFingerprint = ''; $('#liquidcp-summary').addClass('hidden'); $('#liquidcp-line-items').empty(); $('#liquidcp-summary-chips').empty(); $('#liquidcp-warning-list').html('<li>No warnings yet.</li>'); $('#liquidcp-engine-message').removeClass('studio-error').addClass('studio-banner').text('Your estimate will appear here after build inputs are processed.'); $('#liquidcp-save-message').removeClass('studio-error').addClass('studio-banner studio-warn').text('Run an estimate before saving.'); syncActions(); } function validateStep(step){ if(step===1){ if(!$('input[name="client_name"]').val().trim()){ return 'Client name is required.'; } if(!$('input[name="client_email"]').val().trim()){ return 'Client email is required.'; } if(!$('input[name="quote_title"]').val().trim()){ return 'Quote title is required.'; } } if(step===2){ var totalDistance = numberValue('distance_new_aerial') + numberValue('distance_new_underground') + numberValue('distance_existing_aerial') + numberValue('distance_existing_duct'); if(totalDistance <= 0){ return 'At least one route distance is required before pricing.'; } } if(step===3 && !latestEstimate){ return 'Estimate data is missing. Return to Build and try again.'; } return ''; } function syncActions(){ $('#liquidcp-prev-btn').toggle(currentStep > 1); $('#liquidcp-next-btn').toggle(currentStep < 4); $('#liquidcp-save-btn').toggleClass('hidden', currentStep !== 4); $('#liquidcp-save-btn').prop('disabled', !latestEstimate || isEstimating); $('#liquidcp-next-btn').prop('disabled', isEstimating); $('#liquidcp-prev-btn').prop('disabled', isEstimating); } function setStep(step){ currentStep = step; $('[data-step]').removeClass('active'); $('[data-step="' + step + '"]').addClass('active'); $('[data-step-pill]').removeClass('active'); $('[data-step-pill="' + step + '"]').addClass('active'); syncActions(); setValidation(''); window.scrollTo({ top: 0, behavior: 'smooth' }); } function updateCsrf(csrf){ if(csrf){ $('#liquidcp-csrf-token').attr('name', csrf.token_name).val(csrf.hash); } } function categoryTotal(items){ var total = 0; $.each(items, function(_, item){ total += Number(item.amount || 0); }); return total; } function renderLineItems(lineItems){ var order = ['labour','materials','admin','wayleave','equipment']; var html = ''; $.each(order, function(_, category){ var items = lineItems[category] || []; html += '<div class="line-category"><div class="line-head"><div><strong>' + category.charAt(0).toUpperCase() + category.slice(1) + '</strong></div><div><span style="display:block;font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:rgba(20,35,59,.58);margin-bottom:4px;">Category total</span><strong>' + formatMoney(categoryTotal(items)) + '</strong></div></div><div class="table-responsive"><table><thead><tr><th>Item</th><th>Qty</th><th>Unit</th><th>Rate</th><th>Amount</th></tr></thead><tbody>'; if(!items.length){ html += '<tr><td colspan="5">No line items returned for this category.</td></tr>'; } $.each(items, function(_, item){ html += '<tr><td>' + item.label + '</td><td>' + Number(item.quantity).toLocaleString() + '</td><td>' + item.unit + '</td><td>' + formatMoney(item.unit_rate) + '</td><td>' + formatMoney(item.amount) + '</td></tr>'; }); html += '</tbody></table></div></div>'; }); $('#liquidcp-line-items').html(html); } function renderEstimate(estimate){ latestEstimate = estimate; estimateFingerprint = buildFingerprint(); $('#liquidcp-summary').removeClass('hidden'); $('#metric-labour').text(formatMoney(estimate.labour_total)); $('#metric-materials').text(formatMoney(estimate.materials_total)); $('#metric-admin').text(formatMoney(estimate.admin_total)); $('#metric-wayleave').text(formatMoney(estimate.wayleave_total)); $('#metric-vat').text(formatMoney(estimate.vat)); $('#metric-total').text(formatMoney(estimate.total_due)); $('#metric-net-build-cost').text(formatMoney(estimate.net_build_cost)); $('#metric-roi-months').text(estimate.roi_months === null ? 'N/A' : Number(estimate.roi_months).toFixed(2)); $('#metric-roi-years').text(estimate.roi_years === null ? 'N/A' : Number(estimate.roi_years).toFixed(3)); renderLineItems(estimate.line_items); $('#liquidcp-summary-chips').html('<span class="studio-chip" style="margin:0 8px 8px 0;">Ruleset ' + estimate.rule_set_version + '</span><span class="studio-chip" style="margin:0 8px 8px 0;">Engine ' + estimate.engine_version + '</span><span class="studio-chip" style="margin:0 8px 8px 0;">Latency ' + Number(estimate._duration_ms || 0) + 'ms</span>'); var warnings = estimate.warnings || []; var warningHtml = !warnings.length ? '<li>No warnings returned.</li>' : ''; $.each(warnings, function(_, warning){ warningHtml += '<li>' + warning + '</li>'; }); $('#liquidcp-warning-list').html(warningHtml); $('#liquidcp-engine-message').removeClass('studio-error').addClass('studio-banner').text(warnings.length ? 'Estimate calculated. Review the warnings before saving.' : 'Estimate calculated successfully.'); $('#liquidcp-save-message').removeClass('studio-error').addClass('studio-banner studio-warn').text('Estimate is ready to save.'); syncActions(); } function submitTo(url, onSuccess, onError){ $.ajax({ url:url, method:'POST', data:$('#liquidcp-wizard-form').serialize(), dataType:'json' }).done(function(response){ updateCsrf(response.csrf); if(!response.success){ throw new Error(response.message || 'Request failed.'); } onSuccess(response); }).fail(function(xhr){ var message = 'Request failed.'; if(xhr.responseJSON && xhr.responseJSON.message){ message = xhr.responseJSON.message; updateCsrf(xhr.responseJSON.csrf); if(xhr.responseJSON.redirect_url){ window.location.href = xhr.responseJSON.redirect_url; return; } } if(onError){ onError(message); return; } $('#liquidcp-engine-message, #liquidcp-save-message').removeClass('studio-banner studio-warn').addClass('studio-error').text(message); }); } function setEstimatingState(active){ isEstimating = active; $('#liquidcp-next-btn').text(active ? 'Calculating...' : defaultNextLabel); syncActions(); } function runEstimateAndAdvance(){ var message = validateStep(2); if(message){ setValidation(message); return; } setEstimatingState(true); $('#liquidcp-engine-message').removeClass('studio-error').addClass('studio-banner').text('Calculating estimate from your build inputs...'); submitTo('<?php echo site_url('liquidcp/estimate'); ?>', function(response){ renderEstimate(response.estimate); setEstimatingState(false); setStep(3); }, function(message){ setEstimatingState(false); setValidation(message); $('#liquidcp-engine-message').removeClass('studio-banner').addClass('studio-error').text(message); }); } $('#liquidcp-wizard-form').on('input change', 'input, select', function(){ if (estimateFingerprint && buildFingerprint() !== estimateFingerprint) { invalidateEstimate(); } }); $('#liquidcp-next-btn').on('click', function(){ var message = validateStep(currentStep); if(message){ setValidation(message); return; } if(currentStep === 2){ runEstimateAndAdvance(); return; } if(currentStep < 4){ setStep(currentStep + 1); } }); $('#liquidcp-prev-btn').on('click', function(){ if(currentStep > 1){ setStep(currentStep - 1); } }); $('#liquidcp-save-btn').on('click', function(){ if(!latestEstimate){ $('#liquidcp-save-message').removeClass('studio-banner studio-warn').addClass('studio-error').text('Run an estimate first.'); return; } submitTo('<?php echo site_url('liquidcp/save'); ?>', function(response){ $('#liquidcp-save-results').removeClass('hidden').html('<div class="success-box"><strong>' + response.quote_number + '</strong> saved.<div class="success-actions"><a class="btn btn-secondary" target="_blank" href="' + response.quote_url + '">Open quote</a><a class="btn btn-secondary" target="_blank" href="' + response.pdf_url + '">Open PDF</a><a class="btn btn-primary" href="<?php echo html_escape($dashboard_url); ?>">Back to dashboard</a></div></div>'); }); }); setStep(1); })(jQuery);
</script>
</body>
</html>
